const item = items[0].json;

const required = ['campaign_id', 'name', 'audience_segment', 'start_date', 'end_date', 'budget_usd'];
for (const field of required) {
  if (item[field] === undefined || item[field] === null || item[field] === '') {
    throw new Error(`Missing required field: ${field}`);
  }
}

const budget = Number(item.budget_usd);
if (Number.isNaN(budget) || budget <= 0) {
  throw new Error('budget_usd must be a positive number');
}

let channels = {};
let goals = {};
let simulate_failures = {};
try {
  channels = item.channels ? JSON.parse(item.channels) : {};
} catch (e) {
  throw new Error('channels must be valid JSON');
}

try {
  goals = item.goals ? JSON.parse(item.goals) : {};
} catch (e) {
  throw new Error('goals must be valid JSON');
}

try {
  simulate_failures = item.simulate_failures ? JSON.parse(item.simulate_failures) : {};
} catch (e) {
  throw new Error('simulate_failures must be valid JSON');
}

const enabledChannels = Object.entries(channels).filter(([, enabled]) => Boolean(enabled));
if (enabledChannels.length === 0) {
  throw new Error('At least one campaign channel must be enabled');
}

return [{
  json: {
    ...item,
    budget_usd: budget,
    channels,
    goals,
    simulate_failures,
  },
}];

const campaign = { ...items[0].json };
const channel = 'email';
const startedAt = new Date().toISOString();

try {
  if (!campaign.channels?.email) {
    return [{ json: { ...campaign, channel_results: { ...campaign.channel_results, email: { channel, status: 'skipped', enabled: false, reason: 'Channel disabled' } } } }];
  }

  if (campaign.simulate_failures?.email) {
    throw new Error('Simulated email platform failure');
  }

  const result = {
    channel,
    enabled: true,
    status: 'success',
    idempotency_key: campaign.control.idempotency_keys.email,
    retry_policy: campaign.control.retry_policy,
    started_at: startedAt,
    completed_at: new Date().toISOString(),
    entity: {
      segmentId: 'seg_placeholder',
      campaignId: 'cmp_email_placeholder',
      status: 'draft'
    }
  };

  return [{ json: { ...campaign, email: result.entity, channel_results: { ...campaign.channel_results, email: result } } }];
} catch (error) {
  const result = {
    channel,
    enabled: true,
    status: 'failed',
    idempotency_key: campaign.control?.idempotency_keys?.email,
    retry_policy: campaign.control?.retry_policy,
    started_at: startedAt,
    completed_at: new Date().toISOString(),
    error: error.message
  };
  return [{ json: { ...campaign, email: { enabled: false, error: error.message }, channel_results: { ...campaign.channel_results, email: result } } }];
}

