const c = items[0].json;
const results = c.channel_results ?? {};
const channelOrder = [
  ['email', 'Email'],
  ['ads', 'Ads'],
  ['crm', 'CRM'],
  ['internal_comms', 'Internal comms'],
];

const counts = { success: 0, failed: 0, skipped: 0 };
for (const [key] of channelOrder) {
  const status = results[key]?.status ?? 'missing';
  if (counts[status] !== undefined) counts[status] += 1;
}

const overall_status = counts.failed > 0
  ? (counts.success > 0 ? 'partial_success' : 'failed')
  : 'success';

const lines = [];
lines.push(`# Campaign: ${c.name}`);
lines.push('');
lines.push(`Campaign ID: ${c.control?.campaign_id ?? c.campaign_id}`);
lines.push(`Audience: ${c.audience_segment}`);
lines.push(`Dates: ${c.start_date} → ${c.end_date}`);
lines.push(`Budget: $${c.budget_usd}`);
lines.push(`Overall status: ${overall_status}`);
lines.push('');
lines.push('## Channel status');

for (const [key, label] of channelOrder) {
  const result = results[key];
  if (!result) {
    lines.push(`- ${label}: missing result`);
    continue;
  }

  if (result.status === 'success') {
    lines.push(`- ${label}: success (idempotency key: ${result.idempotency_key})`);
  } else if (result.status === 'failed') {
    lines.push(`- ${label}: failed (${result.error})`);
  } else if (result.status === 'skipped') {
    lines.push(`- ${label}: skipped (${result.reason})`);
  } else {
    lines.push(`- ${label}: ${result.status}`);
  }
}

lines.push('');
lines.push('## Control notes');
lines.push(`- Retry policy: ${c.control?.retry_policy?.max_attempts ?? 3} attempts with ${c.control?.retry_policy?.backoff ?? 'exponential'} backoff for transient API failures.`);
lines.push('- Idempotency keys are generated per campaign/channel to avoid duplicate creation after retries.');
lines.push('- Failed branches are captured in the final summary instead of masking successful branches.');

const summary_markdown = lines.join('\n');

return [{
  json: {
    ...c,
    overall_status,
    summary_markdown,
  },
}];

const campaign = { ...items[0].json };
const generatedAt = new Date().toISOString();
const campaignId = String(campaign.campaign_id).trim();

const branchNames = ['email', 'ads', 'crm', 'internal_comms'];
const idempotencyKeys = Object.fromEntries(
  branchNames.map(channel => [channel, `${campaignId}:${channel}:${campaign.start_date}`])
);

const retryPolicy = {
  max_attempts: 3,
  backoff: 'exponential',
  retry_on: ['429', '408', '5xx', 'network_timeout'],
  notes: 'Use this policy on real HTTP/native connector nodes for transient external API failures.'
};

return [{
  json: {
    ...campaign,
    control: {
      campaign_id: campaignId,
      generated_at: generatedAt,
      idempotency_keys: idempotencyKeys,
      retry_policy: retryPolicy,
    },
    channel_results: {},
  },
}];

const source = items[0]?.json ?? {};
const auditRecord = {
  audit_type: 'campaign_orchestration_result',
  logged_at: new Date().toISOString(),
  campaign_id: source.control?.campaign_id ?? source.campaign_id,
  campaign_name: source.name,
  overall_status: source.overall_status,
  channel_results: source.channel_results,
  idempotency_keys: source.control?.idempotency_keys,
  retry_policy: source.control?.retry_policy,
  summary_markdown: source.summary_markdown,
  source_payload: {
    audience_segment: source.audience_segment,
    start_date: source.start_date,
    end_date: source.end_date,
    budget_usd: source.budget_usd,
    channels: source.channels,
    goals: source.goals,
  },
};

return [{
  json: {
    ...source,
    audit_record: auditRecord,
    audit_status: 'ready_for_durable_store',
  },
}];
